import React from 'react';



const PriceCard = () => {
    return (

        <div className="pricing">
            <div className="class-container">

                <div className="card">
                    <h3> - Basic - </h3>
                    <span className="bar"></span>
                    <p className = "btc" > $ 100</p>
                    <p>- 3 Days -</p>
                    <p>- 3 Pages -</p>
                    <p>- Featured -</p>
                    <p>- Responsive Design -</p>
                </div>
            </div>
        </div>
    )
}

export default PriceCard;
